-- ===== functions =====
CREATE OR REPLACE FUNCTION "public"."advisory_lock_fixture"("lock_key" bigint) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
begin
  perform pg_advisory_xact_lock(lock_key);
end;
$$;

CREATE OR REPLACE FUNCTION "public"."inspect_worker_db_context"() RETURNS TABLE("is_replica" boolean, "isolation" "text", "txn" bigint, "ts" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    AS $$
  select
    pg_is_in_recovery() as is_replica,
    current_setting('transaction_isolation') as isolation,
    txid_current() as txn,
    now() as ts;
$$;

CREATE OR REPLACE FUNCTION "public"."purge_user_auth_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  delete from public.user_auth_snapshot where user_id = old.id;
  return old;
end;
$$;

CREATE OR REPLACE FUNCTION "public"."sync_user_auth_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  insert into public.user_auth_snapshot (user_id, email, status, created_at, last_sign_in_at, updated_at)
  values (
    new.id,
    new.email,
    coalesce(new.raw_user_meta_data->>'status', 'active'),
    new.created_at,
    new.last_sign_in_at,
    now()
  )
  on conflict (user_id) do update
  set email = excluded.email,
      status = excluded.status,
      created_at = excluded.created_at,
      last_sign_in_at = excluded.last_sign_in_at,
      updated_at = now();
  return new;
end;
$$;

CREATE OR REPLACE FUNCTION "public"."touch_link_in_bio_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  new.updated_at = now();
  return new;
end;
$$;

