-- ===== policies =====
CREATE POLICY "Auth rate limits service only" ON "public"."auth_rate_limits" USING (("auth"."role"() = 'service_role'::"text")) WITH CHECK (("auth"."role"() = 'service_role'::"text"));

CREATE POLICY "Brand profile accessible by account" ON "public"."brand_profile" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "Campaigns accessible by account" ON "public"."campaigns" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "Content templates accessible by account" ON "public"."content_templates" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "Content variants accessible via parent" ON "public"."content_variants" USING ((("auth"."role"() = 'service_role'::"text") OR (EXISTS ( SELECT 1
   FROM "public"."content_items" "ci"
  WHERE (("ci"."id" = "content_variants"."content_item_id") AND ("ci"."account_id" = "public"."current_account_id"())))))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR (EXISTS ( SELECT 1
   FROM "public"."content_items" "ci"
  WHERE (("ci"."id" = "content_variants"."content_item_id") AND ("ci"."account_id" = "public"."current_account_id"()))))));

CREATE POLICY "Fixtures accessible via tournament account" ON "public"."tournament_fixtures" USING ((("auth"."role"() = 'service_role'::"text") OR (EXISTS ( SELECT 1
   FROM "public"."tournaments" "t"
  WHERE (("t"."id" = "tournament_fixtures"."tournament_id") AND ("t"."account_id" = "public"."current_account_id"())))))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR (EXISTS ( SELECT 1
   FROM "public"."tournaments" "t"
  WHERE (("t"."id" = "tournament_fixtures"."tournament_id") AND ("t"."account_id" = "public"."current_account_id"()))))));

CREATE POLICY "Management app connections service only" ON "public"."management_app_connections" USING (("auth"."role"() = 'service_role'::"text")) WITH CHECK (("auth"."role"() = 'service_role'::"text"));

CREATE POLICY "Media assets accessible by account" ON "public"."media_assets" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "Posting defaults accessible by account" ON "public"."posting_defaults" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "Tournaments accessible by account owner" ON "public"."tournaments" USING ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("account_id" = "public"."current_account_id"())));

CREATE POLICY "User auth snapshot readable by authenticated" ON "public"."user_auth_snapshot" FOR SELECT TO "authenticated", "service_role" USING (true);

CREATE POLICY "Users can manage their own ad account" ON "public"."meta_ad_accounts" USING (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Users can manage their own ad sets" ON "public"."ad_sets" USING ((EXISTS ( SELECT 1
   FROM "public"."campaigns" "c"
  WHERE (("c"."id" = "ad_sets"."campaign_id") AND ("c"."account_id" = "public"."current_account_id"())))));

CREATE POLICY "Users can manage their own ads" ON "public"."ads" USING ((EXISTS ( SELECT 1
   FROM ("public"."ad_sets" "ads2"
     JOIN "public"."campaigns" "c" ON (("c"."id" = "ads2"."campaign_id")))
  WHERE (("ads2"."id" = "ads"."adset_id") AND ("c"."account_id" = "public"."current_account_id"())))));

CREATE POLICY "Users can manage their own campaigns" ON "public"."campaigns" USING (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Users can manage their own meta campaigns" ON "public"."meta_campaigns" USING (("account_id" = "public"."current_account_id"())) WITH CHECK (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Users can read own reviews" ON "public"."gbp_reviews" FOR SELECT USING ((("auth"."role"() = 'service_role'::"text") OR ("business_profile_id" = "public"."current_account_id"())));

CREATE POLICY "Users can update own reviews" ON "public"."gbp_reviews" FOR UPDATE USING ((("auth"."role"() = 'service_role'::"text") OR ("business_profile_id" = "public"."current_account_id"()))) WITH CHECK ((("auth"."role"() = 'service_role'::"text") OR ("business_profile_id" = "public"."current_account_id"())));

CREATE POLICY "Users can view their own booking conversions" ON "public"."booking_conversion_events" FOR SELECT USING (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Users can view their own optimisation actions" ON "public"."meta_optimisation_actions" USING (("account_id" = "public"."current_account_id"())) WITH CHECK (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Users can view their own optimisation runs" ON "public"."meta_optimisation_runs" USING (("account_id" = "public"."current_account_id"())) WITH CHECK (("account_id" = "public"."current_account_id"()));

CREATE POLICY "Worker heartbeats managed by service role" ON "public"."worker_heartbeats" USING (("auth"."role"() = 'service_role'::"text")) WITH CHECK (("auth"."role"() = 'service_role'::"text"));

-- ===== triggers =====
CREATE OR REPLACE TRIGGER "tournament_fixtures_updated_at" BEFORE UPDATE ON "public"."tournament_fixtures" FOR EACH ROW EXECUTE FUNCTION "public"."set_updated_at"();

CREATE OR REPLACE TRIGGER "tournaments_updated_at" BEFORE UPDATE ON "public"."tournaments" FOR EACH ROW EXECUTE FUNCTION "public"."set_updated_at"();

