ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "last_error" "text";

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "next_attempt_at" timestamp with time zone;

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "placement" "text";

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "provider_response" "jsonb";

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "status" "text";

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "updated_at" timestamp with time zone;

ALTER TABLE "public"."publish_jobs" ADD COLUMN IF NOT EXISTS "variant_id" "uuid";

-- ===== views =====
CREATE OR REPLACE VIEW "public"."publish_jobs_with_variant" AS
 SELECT "pj"."id",
    "pj"."content_item_id",
    "pj"."attempt",
    "pj"."status",
    "pj"."last_error",
    "pj"."provider_response",
    "pj"."next_attempt_at",
    "pj"."created_at",
    "pj"."updated_at",
    "pj"."placement",
    "pj"."variant_id",
    "cv"."media_ids"
   FROM ("public"."publish_jobs" "pj"
     JOIN "public"."content_variants" "cv" ON (("cv"."id" = "pj"."variant_id")));

